        { en: 'Prostatectomy', ar: 'استئصال البروستات', c: 5500 },
        { en: 'Cataract Surgery', ar: 'إزالة المياه البيضاء', c: 900 }
    ];
    const stmt = db.prepare('INSERT INTO operations_catalog (name_en, name_ar, base_cost) VALUES (?, ?, ?)');
    ops.forEach(o => stmt.run(o.en, o.ar, o.c));
  }

  // 9. Payment Methods (Requested: Cash, Bankak, Fawry, OCash, Insurance)
  const pmCount = db.prepare('SELECT count(*) as count FROM payment_methods').get().count;
  if (pmCount === 0) {
    const pms = [
      { en: 'Cash', ar: 'نقدي' },
      { en: 'Bankak Transfer', ar: 'تحويل بنكك' },
      { en: 'Fawry Pay', ar: 'فوري' },
      { en: 'OCash', ar: 'أو كاش' },
      { en: 'Insurance', ar: 'تأمين' },
      { en: 'ATM/Card', ar: 'بطاقة صراف' }
    ];
    const stmt = db.prepare('INSERT INTO payment_methods (name_en, name_ar, is_active) VALUES (?, ?, 1)');
    pms.forEach(p => stmt.run(p.en, p.ar));
  }

  // 10. Default Tax Rate
  const taxCount = db.prepare('SELECT count(*) as count FROM tax_rates').get().count;
  if (taxCount === 0) {
    db.prepare('INSERT INTO tax_rates (name_en, name_ar, rate, is_active) VALUES (?, ?, ?, ?)').run('Standard VAT', 'ضريبة القيمة المضافة', 15, 1);
  }

  // 11. Initial Configuration
  const settingsCount = db.prepare('SELECT count(*) as count FROM system_settings').get().count;
  if (settingsCount === 0) {
    const stmt = db.prepare('INSERT INTO system_settings (key, value) VALUES (?, ?)');
    stmt.run('hospitalName', 'AllCare General Hospital');
    stmt.run('hospitalAddress', 'Atbara, Sudan - Main Street');
    stmt.run('hospitalPhone', '+249 912345678');
  }
};

module.exports = { db, initDB };

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary component to catch rendering errors in the component tree.
 */
// Fix: Explicitly extend React.Component and provide types for props and state to ensure base class properties like setState and props are correctly inherited and recognized
export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  // Fix: Initialize state as a class property to ensure it is correctly recognized as a member of the class instance
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  /**
   * Static method to update state when an error occurs during rendering.
   */
  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  /**
   * Lifecycle method to log error details.
   */
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  /**
   * Resets the error state to allow the application to attempt re-rendering.
   */
  public handleReload = () => {
    // Fix: setState is correctly recognized as a member inherited from React.Component
    this.setState({ hasError: false, error: null });
  }

  public render() {
    // Fix: state property is recognized through proper inheritance from React.Component
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900 p-4">
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl max-w-md w-full text-center border border-slate-200 dark:border-slate-700">
            <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600 dark:text-red-400">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h1>
            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
              The application encountered an unexpected error.
            </p>

            {this.state.error && (
                <div className="bg-slate-100 dark:bg-slate-950 p-3 rounded-lg text-left text-xs font-mono text-red-600 dark:text-red-400 overflow-auto max-h-32 mb-6">
                    {this.state.error.toString()}
                </div>
            )}

            <button 
              onClick={this.handleReload}
              className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all w-full"
            >
              <RefreshCw size={18} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    // Fix: props.children is now correctly identified via inheritance from React.Component
    return this.props.children;
  }
}
